// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {
	// Create a user (admin only)
	// (POST /admin/users)
	CreateUser(ctx context.Context, request CreateUserRequestObject) (CreateUserResponseObject, error)
	// List case files (filterable)
	// (GET /casefiles)
	ListCaseFiles(ctx context.Context, request ListCaseFilesRequestObject) (ListCaseFilesResponseObject, error)
	// Open a case file
	// (POST /casefiles)
	CreateCaseFile(ctx context.Context, request CreateCaseFileRequestObject) (CreateCaseFileResponseObject, error)
	// Get a case file by ID
	// (GET /casefiles/{id})
	GetCaseFile(ctx context.Context, request GetCaseFileRequestObject) (GetCaseFileResponseObject, error)
	// Append one evidence to a case file
	// (POST /casefiles/{id}/evidence)
	IngestCaseFileEvidence(ctx context.Context, request IngestCaseFileEvidenceRequestObject) (IngestCaseFileEvidenceResponseObject, error)
	// Finalize a case file
	// (POST /casefiles/{id}/finalize)
	FinalizeCaseFile(ctx context.Context, request FinalizeCaseFileRequestObject) (FinalizeCaseFileResponseObject, error)
	// List findings across projects (filterable)
	// (GET /findings)
	ListFindings(ctx context.Context, request ListFindingsRequestObject) (ListFindingsResponseObject, error)
	// List gavelspaces
	// (GET /gavelspaces)
	ListGavelspaces(ctx context.Context, request ListGavelspacesRequestObject) (ListGavelspacesResponseObject, error)
	// Create a gavelspace (admin only)
	// (POST /gavelspaces)
	CreateGavelspace(ctx context.Context, request CreateGavelspaceRequestObject) (CreateGavelspaceResponseObject, error)
	// Get a gavelspace by name
	// (GET /gavelspaces/{name})
	GetGavelspace(ctx context.Context, request GetGavelspaceRequestObject) (GetGavelspaceResponseObject, error)
	// Register a project in a gavelspace (admin only)
	// (POST /gavelspaces/{name}/projects)
	RegisterGavelspaceProject(ctx context.Context, request RegisterGavelspaceProjectRequestObject) (RegisterGavelspaceProjectResponseObject, error)
	// Remove a project from a gavelspace (admin only)
	// (DELETE /gavelspaces/{name}/projects/{project_id})
	RemoveGavelspaceProject(ctx context.Context, request RemoveGavelspaceProjectRequestObject) (RemoveGavelspaceProjectResponseObject, error)
	// Liveness probe
	// (GET /health)
	GetHealth(ctx context.Context, request GetHealthRequestObject) (GetHealthResponseObject, error)
	// Get the currently authenticated user
	// (GET /me)
	GetMe(ctx context.Context, request GetMeRequestObject) (GetMeResponseObject, error)
	// Change the current user's password
	// (POST /me/password)
	ChangeMyPassword(ctx context.Context, request ChangeMyPasswordRequestObject) (ChangeMyPasswordResponseObject, error)
	// List the current user's API tokens
	// (GET /me/tokens)
	ListMyTokens(ctx context.Context, request ListMyTokensRequestObject) (ListMyTokensResponseObject, error)
	// Create a new API token for the current user
	// (POST /me/tokens)
	CreateMyToken(ctx context.Context, request CreateMyTokenRequestObject) (CreateMyTokenResponseObject, error)
	// Revoke one of the current user's API tokens
	// (DELETE /me/tokens/{id})
	DeleteMyToken(ctx context.Context, request DeleteMyTokenRequestObject) (DeleteMyTokenResponseObject, error)
	// List pleadings (filterable)
	// (GET /pleadings)
	ListPleadings(ctx context.Context, request ListPleadingsRequestObject) (ListPleadingsResponseObject, error)
	// Get a pleading by ID
	// (GET /pleadings/{id})
	GetPleading(ctx context.Context, request GetPleadingRequestObject) (GetPleadingResponseObject, error)
	// Resolve a pleading (admin only)
	// (PATCH /pleadings/{id})
	ResolvePleading(ctx context.Context, request ResolvePleadingRequestObject) (ResolvePleadingResponseObject, error)
	// List projects
	// (GET /projects)
	ListProjects(ctx context.Context, request ListProjectsRequestObject) (ListProjectsResponseObject, error)
	// Create a project (admin only)
	// (POST /projects)
	CreateProject(ctx context.Context, request CreateProjectRequestObject) (CreateProjectResponseObject, error)
	// Get a project by key
	// (GET /projects/{key})
	GetProject(ctx context.Context, request GetProjectRequestObject) (GetProjectResponseObject, error)
	// Get the baseline (last casefile on a branch)
	// (GET /projects/{key}/baseline)
	GetProjectBaseline(ctx context.Context, request GetProjectBaselineRequestObject) (GetProjectBaselineResponseObject, error)
	// List casefiles for a project
	// (GET /projects/{key}/casefiles)
	ListProjectCaseFiles(ctx context.Context, request ListProjectCaseFilesRequestObject) (ListProjectCaseFilesResponseObject, error)
	// Replace the project's declared languages (admin only)
	// (PUT /projects/{key}/languages)
	UpdateProjectLanguages(ctx context.Context, request UpdateProjectLanguagesRequestObject) (UpdateProjectLanguagesResponseObject, error)
	// List pleadings for a project
	// (GET /projects/{key}/pleadings)
	ListProjectPleadings(ctx context.Context, request ListProjectPleadingsRequestObject) (ListProjectPleadingsResponseObject, error)
	// File a new pleading against the project (admin only)
	// (POST /projects/{key}/pleadings)
	FileProjectPleading(ctx context.Context, request FileProjectPleadingRequestObject) (FileProjectPleadingResponseObject, error)
	// Replace the project's quality gate (admin only)
	// (PUT /projects/{key}/quality-gate)
	UpdateProjectQualityGate(ctx context.Context, request UpdateProjectQualityGateRequestObject) (UpdateProjectQualityGateResponseObject, error)
	// Fetch a source-blob from a commit
	// (GET /projects/{key}/source)
	GetProjectSource(ctx context.Context, request GetProjectSourceRequestObject) (GetProjectSourceResponseObject, error)
	// Upload source files for a commit
	// (POST /projects/{key}/source)
	UploadProjectSource(ctx context.Context, request UploadProjectSourceRequestObject) (UploadProjectSourceResponseObject, error)
	// Cross-resource search
	// (GET /search)
	Search(ctx context.Context, request SearchRequestObject) (SearchResponseObject, error)
	// Create a session (log in)
	// (POST /sessions)
	CreateSession(ctx context.Context, request CreateSessionRequestObject) (CreateSessionResponseObject, error)
	// Delete the current session (log out)
	// (DELETE /sessions/current)
	DeleteCurrentSession(ctx context.Context, request DeleteCurrentSessionRequestObject) (DeleteCurrentSessionResponseObject, error)
}

type StrictHandlerFunc func(ctx context.Context, w http.ResponseWriter, r *http.Request, request any) (any, error)
type StrictMiddlewareFunc func(f StrictHandlerFunc, operationID string) StrictHandlerFunc

type StrictHTTPServerOptions struct {
	RequestErrorHandlerFunc  func(w http.ResponseWriter, r *http.Request, err error)
	ResponseErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

func NewStrictHandler(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: StrictHTTPServerOptions{
		RequestErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		},
		ResponseErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusInternalServerError)
		},
	}}
}

func NewStrictHandlerWithOptions(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc, options StrictHTTPServerOptions) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: options}
}

